import{_ as e,o as d,c as a,a4 as o}from"./chunks/framework.CDpUjPX_.js";const h=JSON.parse('{"title":"AutoDiscovery — Descoberta Autonoma de Sites Pirata","description":"","frontmatter":{},"headers":[],"relativePath":"motores/motor-24-auto-discovery.md","filePath":"motores/motor-24-auto-discovery.md"}'),r={name:"motores/motor-24-auto-discovery.md"};function i(s,t,c,l,n,p){return d(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="autodiscovery-—-descoberta-autonoma-de-sites-pirata" tabindex="-1">AutoDiscovery — Descoberta Autonoma de Sites Pirata <a class="header-anchor" href="#autodiscovery-—-descoberta-autonoma-de-sites-pirata" aria-label="Permalink to &quot;AutoDiscovery — Descoberta Autonoma de Sites Pirata&quot;">​</a></h1><h2 id="metadados" tabindex="-1">Metadados <a class="header-anchor" href="#metadados" aria-label="Permalink to &quot;Metadados&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td><strong>Motor ID</strong></td><td>24</td></tr><tr><td><strong>Nome</strong></td><td>AutoDiscovery</td></tr><tr><td><strong>Slug</strong></td><td>autodiscovery</td></tr><tr><td><strong>Categoria</strong></td><td>Discovery</td></tr><tr><td><strong>Status</strong></td><td>ATIVO</td></tr><tr><td><strong>Frequencia</strong></td><td>Sob Demanda</td></tr><tr><td><strong>Fila Celery</strong></td><td>celery</td></tr><tr><td><strong>Dependencias Externas</strong></td><td>DNS, Subdomain enumeration</td></tr><tr><td><strong>Chaves de Config</strong></td><td>—</td></tr></tbody></table><h2 id="visao-geral" tabindex="-1">Visao Geral <a class="header-anchor" href="#visao-geral" aria-label="Permalink to &quot;Visao Geral&quot;">​</a></h2><p>Motor 100% autonomo que descobre, classifica e alimenta novos sites/forums/canais de pirataria para todos os outros motores, sem intervencao humana.</p><h2 id="pipeline-completo" tabindex="-1">Pipeline Completo <a class="header-anchor" href="#pipeline-completo" aria-label="Permalink to &quot;Pipeline Completo&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Descoberta    →  Scoring (1h)  →  Quarentena (24h)  →  Auto-Approve (≥0.80)  →  Feed (30min)  →  Monitoramento</span></span>
<span class="line"><span>   ↑                                                                                                    ↓</span></span>
<span class="line"><span>   └─── Resurrection (7d) ←── Dead (10 falhas) ←── Offline (3 falhas) ←── Health Check (24h) ←─────────┘</span></span>
<span class="line"><span>                                                                                                        ↓</span></span>
<span class="line"><span>                                                              Feedback Loop (24h): detecções ↑ score, FPs ↓ score</span></span></code></pre></div><h2 id="modelo-discoverytarget" tabindex="-1">Modelo: DiscoveryTarget <a class="header-anchor" href="#modelo-discoverytarget" aria-label="Permalink to &quot;Modelo: DiscoveryTarget&quot;">​</a></h2><p>Tabela <code>discovery_targets</code> — evolucao do <code>DiscoveredSource</code> (SourceIntel).</p><h3 id="campos-principais" tabindex="-1">Campos principais <a class="header-anchor" href="#campos-principais" aria-label="Permalink to &quot;Campos principais&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Tipo</th><th>Descricao</th></tr></thead><tbody><tr><td>url</td><td>TEXT</td><td>URL unica do target</td></tr><tr><td>domain</td><td>VARCHAR(255)</td><td>Dominio extraido da URL</td></tr><tr><td>platform</td><td>VARCHAR(30)</td><td>web, telegram, discord, reddit, darkweb, etc.</td></tr><tr><td>target_type</td><td>VARCHAR(30)</td><td>site, forum, tube, leak_aggregator, escort, etc.</td></tr><tr><td>source_module</td><td>VARCHAR(30)</td><td>dork, dns, link, social, darkweb, admin, ct_log</td></tr><tr><td>risk_score</td><td>FLOAT</td><td>0.0-1.0 (scoring automatico + ajuste adaptativo)</td></tr><tr><td>confidence</td><td>FLOAT</td><td>0.0-1.0 (confianca na classificacao)</td></tr><tr><td>status</td><td>VARCHAR(20)</td><td>pending, approved, rejected, monitoring, dead</td></tr><tr><td>auto_approved</td><td>BOOLEAN</td><td>Se foi auto-aprovado por threshold</td></tr><tr><td>feed_to_motors</td><td>JSONB</td><td>Lista de motor IDs para alimentar</td></tr><tr><td>detection_count</td><td>INTEGER</td><td>Contagem de deteccoes reais do monitoramento</td></tr><tr><td>false_positive_count</td><td>INTEGER</td><td>Contagem de falsos positivos</td></tr><tr><td>score_adjustment</td><td>FLOAT</td><td>Delta adaptativo de scoring (-0.20 a +0.20)</td></tr><tr><td>tags</td><td>JSONB</td><td>Tags de classificacao</td></tr></tbody></table><h3 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pending → approved → monitoring ← (resurrection)</span></span>
<span class="line"><span>       → rejected                → dead (10 falhas) → pending (se voltar online)</span></span></code></pre></div><h2 id="api-admin" tabindex="-1">API Admin <a class="header-anchor" href="#api-admin" aria-label="Permalink to &quot;API Admin&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metodo</th><th>Endpoint</th><th>Descricao</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/v1/admin/discovery/targets</code></td><td>Lista com filtros e paginacao</td></tr><tr><td>POST</td><td><code>/api/v1/admin/discovery/targets</code></td><td>Criar target manual</td></tr><tr><td>PUT</td><td><code>/api/v1/admin/discovery/targets/{id}</code></td><td>Atualizar (aprovar, rejeitar)</td></tr><tr><td>DELETE</td><td><code>/api/v1/admin/discovery/targets/{id}</code></td><td>Remover</td></tr><tr><td>POST</td><td><code>/api/v1/admin/discovery/targets/bulk</code></td><td>Import em bulk</td></tr><tr><td>GET</td><td><code>/api/v1/admin/discovery/stats</code></td><td>Estatisticas agregadas</td></tr></tbody></table><h2 id="scoring-pipeline" tabindex="-1">Scoring Pipeline <a class="header-anchor" href="#scoring-pipeline" aria-label="Permalink to &quot;Scoring Pipeline&quot;">​</a></h2><h3 id="sinais-estaticos-pesos" tabindex="-1">Sinais Estaticos (Pesos) <a class="header-anchor" href="#sinais-estaticos-pesos" aria-label="Permalink to &quot;Sinais Estaticos (Pesos)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Sinal</th><th>Peso</th><th>Fonte</th></tr></thead><tbody><tr><td>Keywords de pirataria na URL</td><td>+0.15</td><td>Analise de dominio</td></tr><tr><td>TLD suspeito (.cc, .to, etc.)</td><td>+0.05</td><td>Analise de dominio</td></tr><tr><td>Dominio recente (&lt; 6 meses)</td><td>+0.20</td><td>RDAP Registro.br</td></tr><tr><td>WHOIS com privacidade</td><td>+0.20</td><td>RDAP Registro.br</td></tr><tr><td>Wallet crypto na pagina</td><td>+0.10</td><td>Intel extractor</td></tr><tr><td>Indicadores adultos</td><td>+0.15</td><td>Analise de conteudo</td></tr><tr><td>Cloudflare detectado</td><td>+0.05</td><td>Nameservers</td></tr><tr><td>Dominio .gov/.edu</td><td>-0.20</td><td>Analise de dominio</td></tr><tr><td>Match na allowlist</td><td>-0.30</td><td>Allowlist Kubex</td></tr></tbody></table><h3 id="scoring-adaptativo-feedback-loop" tabindex="-1">Scoring Adaptativo (Feedback Loop) <a class="header-anchor" href="#scoring-adaptativo-feedback-loop" aria-label="Permalink to &quot;Scoring Adaptativo (Feedback Loop)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Sinal</th><th>Peso</th><th>Fonte</th></tr></thead><tbody><tr><td>Deteccao real no monitoramento</td><td>+0.05/deteccao</td><td>Alert.found_url match</td></tr><tr><td>Falso positivo reportado</td><td>-0.10/FP</td><td>Admin feedback</td></tr><tr><td><strong>Cap maximo de ajuste</strong></td><td>±0.20</td><td>Protecao contra drift</td></tr></tbody></table><p>O ajuste e recalculado a cada 24h. O score antigo e removido antes de aplicar o novo (previne drift acumulativo).</p><p>Servico: <code>app/services/discovery_feedback_service.py</code></p><h3 id="auto-approve-com-safety-rails" tabindex="-1">Auto-Approve com Safety Rails <a class="header-anchor" href="#auto-approve-com-safety-rails" aria-label="Permalink to &quot;Auto-Approve com Safety Rails&quot;">​</a></h3><ul><li>Config: <code>DISCOVERY_AUTO_APPROVE_ENABLED=true</code> (ativo por default)</li><li>Threshold: <code>DISCOVERY_AUTO_APPROVE_THRESHOLD=0.80</code></li><li><strong>Quarentena:</strong> Target precisa ter pelo menos <code>DISCOVERY_AUTO_APPROVE_QUARANTINE_HOURS=24</code> horas de idade</li><li><strong>Cap diario:</strong> Maximo <code>DISCOVERY_AUTO_APPROVE_DAILY_CAP=100</code> auto-aprovacoes por dia (Redis counter)</li><li>Targets auto-aprovados recebem <code>status=approved</code>, <code>auto_approved=true</code>, <code>approved_by=auto</code></li></ul><h3 id="servicos" tabindex="-1">Servicos <a class="header-anchor" href="#servicos" aria-label="Permalink to &quot;Servicos&quot;">​</a></h3><ul><li><code>app/services/discovery_scoring_service.py</code> — <code>compute_risk_score()</code></li><li><code>app/services/discovery_feed_service.py</code> — <code>feed_target_to_motors()</code></li><li><code>app/services/discovery_feedback_service.py</code> — <code>compute_score_adjustment()</code></li></ul><h2 id="auto-feed" tabindex="-1">Auto-Feed <a class="header-anchor" href="#auto-feed" aria-label="Permalink to &quot;Auto-Feed&quot;">​</a></h2><p>Quando um target e aprovado (manual ou auto), e roteado para motores de monitoramento:</p><table tabindex="0"><thead><tr><th>Plataforma</th><th>Tipo de Target</th><th>Motores</th></tr></thead><tbody><tr><td>web/darkweb</td><td>site, forum, imageboard</td><td>Crawler (Motor 2)</td></tr><tr><td>web</td><td>tube, leak_aggregator, escort, marketplace, cam</td><td>Crawler + BrandWatch (Motor 4)</td></tr><tr><td>telegram</td><td>channel</td><td>Telegram Monitor (Motor 5)</td></tr><tr><td>discord</td><td>channel</td><td>Discord Monitor (Motor 9)</td></tr><tr><td>reddit</td><td>channel</td><td>Reddit Monitor (Motor 13)</td></tr></tbody></table><h2 id="celery-beat-schedule" tabindex="-1">Celery Beat Schedule <a class="header-anchor" href="#celery-beat-schedule" aria-label="Permalink to &quot;Celery Beat Schedule&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Task</th><th>Intervalo</th><th>Queue</th><th>Descricao</th></tr></thead><tbody><tr><td><code>discovery.trigger_discovery_scan</code></td><td>12 horas</td><td>celery_low</td><td>Social discovery (Telegram/Reddit)</td></tr><tr><td><code>discovery.health_check_sources</code></td><td>24 horas</td><td>celery_low</td><td>Verifica se fontes estao online</td></tr><tr><td><code>discovery.score_pending_targets</code></td><td>1 hora</td><td>celery_low</td><td>Scoring de risk para targets pendentes</td></tr><tr><td><code>discovery.feed_approved_targets</code></td><td>30 minutos</td><td>celery_low</td><td>Alimenta targets aprovados nos motores</td></tr><tr><td><code>discovery.run_dork_spider</code></td><td>6 horas</td><td>celery_low</td><td>Google dorking autonomo via SerpAPI</td></tr><tr><td><code>discovery.resurrect_dead_sources</code></td><td>7 dias</td><td>celery_low</td><td>Re-check de fontes mortas</td></tr><tr><td><code>discovery.recalculate_feedback_scores</code></td><td>24 horas</td><td>celery_low</td><td>Ajuste adaptativo de scores</td></tr></tbody></table><h2 id="modulos-de-descoberta" tabindex="-1">Modulos de Descoberta <a class="header-anchor" href="#modulos-de-descoberta" aria-label="Permalink to &quot;Modulos de Descoberta&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Modulo</th><th>Status</th><th>Intervalo</th><th>Descricao</th></tr></thead><tbody><tr><td>Seed Manual (admin)</td><td>✅ Implementado</td><td>Manual</td><td>Admin cria targets via CRUD ou bulk import</td></tr><tr><td>Telegram MTProto</td><td>✅ Implementado</td><td>12h</td><td>Busca canais por keywords via API do Telegram</td></tr><tr><td>Telegram Indexers</td><td>✅ Implementado</td><td>12h</td><td>Busca canais via TGStat, Telemetr.io e Lyzem</td></tr><tr><td>Reddit Discovery</td><td>✅ Implementado</td><td>12h</td><td>Busca subreddits por keywords</td></tr><tr><td>Cross-Reference</td><td>✅ Implementado</td><td>On-demand</td><td>Analisa outbound links de crawls para novos dominios</td></tr><tr><td><strong>Dork Spider</strong></td><td>✅ Implementado</td><td>6h</td><td>Google dorking autonomo via SerpAPI</td></tr><tr><td>DNS/IP Discovery</td><td>Em avaliacao</td><td>24h</td><td>Descobre dominios por DNS passivo</td></tr><tr><td>Dark Web Discovery</td><td>Em avaliacao</td><td>7d</td><td>Descobre .onion sites novos</td></tr></tbody></table><h3 id="dork-spider-serpapi" tabindex="-1">Dork Spider (SerpAPI) <a class="header-anchor" href="#dork-spider-serpapi" aria-label="Permalink to &quot;Dork Spider (SerpAPI)&quot;">​</a></h3><p>Servico: <code>app/services/dork_spider_service.py</code></p><p>Busca automatica no Google usando dorks configuraveis. Usa SerpAPI (ja integrado para Lens) para evitar bloqueios.</p><p><strong>Fluxo:</strong></p><ol><li>Constroi queries a partir de patterns (com/sem nome de marca)</li><li>Verifica cache Redis (48h) — pula dorks recentes</li><li>Verifica quota SerpAPI mensal</li><li>Executa via SerpAPI (engine=google, gl=br, hl=pt)</li><li>Extrai URLs dos resultados organicos</li><li>Deduplica contra DiscoveryTargets existentes</li><li>Cria novos targets (status=pending, source_module=dork)</li></ol><p><strong>Dork Patterns configuráveis</strong> via <code>DISCOVERY_DORK_PATTERNS</code>:</p><ul><li>Cyberlockers: mega.nz, mediafire.com, gofile.io, pixeldrain.com, bunkr.cr</li><li>Forums de pirataria: simpcity.su, coomer.su, kemono.su, fapello.com</li><li>Pirataria brasileira: <code>inurl:vazou OR inurl:leaked</code>, <code>intext:&quot;pack gratis&quot;</code></li><li>Torrent: 1337x.to</li><li>Genericos (sem marca): <code>intitle:&quot;index of&quot;</code>, <code>&quot;onlyfans leak&quot;</code>, <code>&quot;vazou pack&quot;</code></li></ul><p><strong>Integracao com marcas:</strong> Busca nomes de marcas ativas (<code>MonitoredName.is_active=True</code>) para preencher <code>{query}</code> nos patterns.</p><h3 id="telegram-indexers" tabindex="-1">Telegram Indexers <a class="header-anchor" href="#telegram-indexers" aria-label="Permalink to &quot;Telegram Indexers&quot;">​</a></h3><p>Servico: <code>app/services/telegram_indexer_service.py</code></p><p>Consulta 3 indexadores publicos de canais Telegram em paralelo com retry inteligente:</p><table tabindex="0"><thead><tr><th>Indexador</th><th>URL</th><th>O que faz</th></tr></thead><tbody><tr><td><strong>TGStat</strong></td><td>tgstat.com/search</td><td>Busca canais/grupos com filtro de idioma PT</td></tr><tr><td><strong>Telemetr.io</strong></td><td>telemetr.io/en/channels</td><td>Busca com filtro de idioma + subscribers</td></tr><tr><td><strong>Lyzem</strong></td><td>lyzem.com/search</td><td>Full-text search em mensagens de canais publicos</td></tr></tbody></table><h2 id="dead-source-resurrection" tabindex="-1">Dead Source Resurrection <a class="header-anchor" href="#dead-source-resurrection" aria-label="Permalink to &quot;Dead Source Resurrection&quot;">​</a></h2><p>Fontes marcadas como <code>dead</code> (10 falhas consecutivas) sao re-verificadas a cada 7 dias:</p><ul><li>Se responde com status &lt; 400 → <code>status=pending</code>, <code>is_online=true</code>, <code>consecutive_failures=0</code></li><li>Se continua offline → mantem <code>status=dead</code>, atualiza <code>last_health_check_at</code></li></ul><p>Config: <code>DISCOVERY_RESURRECT_ENABLED=true</code>, <code>DISCOVERY_RESURRECT_CHECK_DAYS=7</code>, <code>DISCOVERY_RESURRECT_MAX_PER_RUN=30</code></p><h2 id="retry-inteligente" tabindex="-1">Retry Inteligente <a class="header-anchor" href="#retry-inteligente" aria-label="Permalink to &quot;Retry Inteligente&quot;">​</a></h2><p>Todas as chamadas HTTP de discovery (indexers, cross-ref) usam <code>app/core/retry_handler.py</code>:</p><ul><li>Exponential backoff: 2s → 4s → 8s (base 2)</li><li>Max retries: 2 (3 tentativas total)</li><li>Retryable: timeout, 429, 500, 502, 503, 504</li><li>Nao retryable: 404, 403, outros permanentes</li></ul><h2 id="rate-limiting-per-platform" tabindex="-1">Rate Limiting Per-Platform <a class="header-anchor" href="#rate-limiting-per-platform" aria-label="Permalink to &quot;Rate Limiting Per-Platform&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Plataforma</th><th>Limite</th><th>Janela</th></tr></thead><tbody><tr><td>Telegram</td><td>30 calls</td><td>1 hora</td></tr><tr><td>Reddit</td><td>60 calls</td><td>1 hora</td></tr><tr><td>SerpAPI Discovery</td><td>200 calls</td><td>1 dia</td></tr><tr><td>SerpAPI Total</td><td>5000 calls</td><td>1 mes</td></tr></tbody></table><h2 id="configuracao-completa" tabindex="-1">Configuracao Completa <a class="header-anchor" href="#configuracao-completa" aria-label="Permalink to &quot;Configuracao Completa&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variavel</th><th>Default</th><th>Descricao</th></tr></thead><tbody><tr><td><code>DISCOVERY_ENABLED</code></td><td><code>true</code></td><td>Master kill-switch</td></tr><tr><td><code>DISCOVERY_AUTO_APPROVE_ENABLED</code></td><td><code>true</code></td><td>Ativa auto-aprovacao</td></tr><tr><td><code>DISCOVERY_AUTO_APPROVE_THRESHOLD</code></td><td><code>0.80</code></td><td>Score minimo para auto-approve</td></tr><tr><td><code>DISCOVERY_AUTO_APPROVE_DAILY_CAP</code></td><td><code>100</code></td><td>Max auto-aprovacoes/dia</td></tr><tr><td><code>DISCOVERY_AUTO_APPROVE_QUARANTINE_HOURS</code></td><td><code>24</code></td><td>Idade minima para auto-approve</td></tr><tr><td><code>DISCOVERY_CROSSREF_ENABLED</code></td><td><code>true</code></td><td>Cross-ref do Crawler</td></tr><tr><td><code>DISCOVERY_HEALTH_FAILURE_THRESHOLD</code></td><td><code>3</code></td><td>Falhas para marcar offline</td></tr><tr><td><code>DISCOVERY_HEALTH_DEAD_THRESHOLD</code></td><td><code>10</code></td><td>Falhas para marcar dead</td></tr><tr><td><code>DISCOVERY_RESURRECT_ENABLED</code></td><td><code>true</code></td><td>Ativa ressurreicao</td></tr><tr><td><code>DISCOVERY_RESURRECT_CHECK_DAYS</code></td><td><code>7</code></td><td>Intervalo de re-check</td></tr><tr><td><code>DISCOVERY_RESURRECT_MAX_PER_RUN</code></td><td><code>30</code></td><td>Max dead sources por run</td></tr><tr><td><code>DISCOVERY_SCORING_ENABLED</code></td><td><code>true</code></td><td>Ativa scoring automatico</td></tr><tr><td><code>DISCOVERY_FEED_ENABLED</code></td><td><code>true</code></td><td>Ativa auto-feed</td></tr><tr><td><code>DISCOVERY_FEED_AUTO_ON_APPROVE</code></td><td><code>true</code></td><td>Feed imediato apos aprovacao</td></tr><tr><td><code>DISCOVERY_DORK_SPIDER_ENABLED</code></td><td><code>true</code></td><td>Ativa dork spider</td></tr><tr><td><code>DISCOVERY_DORK_SPIDER_MAX_DORKS_PER_RUN</code></td><td><code>10</code></td><td>Max queries/run</td></tr><tr><td><code>DISCOVERY_DORK_SPIDER_CACHE_HOURS</code></td><td><code>48</code></td><td>Cache de dork queries</td></tr><tr><td><code>DISCOVERY_FEEDBACK_ENABLED</code></td><td><code>true</code></td><td>Ativa feedback loop</td></tr><tr><td><code>DISCOVERY_FEEDBACK_DETECTION_BONUS</code></td><td><code>0.05</code></td><td>Bonus por deteccao</td></tr><tr><td><code>DISCOVERY_FEEDBACK_FALSE_POSITIVE_PENALTY</code></td><td><code>-0.10</code></td><td>Penalidade por FP</td></tr><tr><td><code>DISCOVERY_FEEDBACK_MAX_ADJUSTMENT</code></td><td><code>0.20</code></td><td>Max ajuste adaptativo</td></tr><tr><td><code>DISCOVERY_SOCIAL_KEYWORDS</code></td><td>(lista)</td><td>Keywords unificadas social</td></tr><tr><td><code>DISCOVERY_REDDIT_KEYWORDS</code></td><td>(lista)</td><td>Keywords Reddit</td></tr><tr><td><code>DISCOVERY_TELEGRAM_INDEXER_KEYWORDS</code></td><td>(lista)</td><td>Keywords indexers Telegram</td></tr><tr><td><code>DISCOVERY_RATE_LIMIT_TELEGRAM_PER_HOUR</code></td><td><code>30</code></td><td>Rate limit Telegram</td></tr><tr><td><code>DISCOVERY_RATE_LIMIT_REDDIT_PER_HOUR</code></td><td><code>60</code></td><td>Rate limit Reddit</td></tr><tr><td><code>DISCOVERY_RATE_LIMIT_SERPAPI_PER_DAY</code></td><td><code>200</code></td><td>Rate limit SerpAPI discovery</td></tr></tbody></table><h2 id="seguranca-lgpd" tabindex="-1">Seguranca &amp; LGPD <a class="header-anchor" href="#seguranca-lgpd" aria-label="Permalink to &quot;Seguranca &amp; LGPD&quot;">​</a></h2><ul><li>Nao armazena dados pessoais de sites de pirataria</li><li>SSRF guard aplicado em todas URLs candidatas (RFC-1918, loopback, IMDS)</li><li>Audit logs de todas acoes admin (approve, reject, import, delete)</li><li>Auto-approve com safety rails: quarentena 24h, cap diario 100</li><li>Rate limiting per-platform (Telegram 30/h, Reddit 60/h, SerpAPI 200/d)</li><li>PII nunca em logs — apenas URLs e dominios</li></ul><h2 id="testes" tabindex="-1">Testes <a class="header-anchor" href="#testes" aria-label="Permalink to &quot;Testes&quot;">​</a></h2><ul><li><strong>Unit tests:</strong> <code>tests/engines/test_auto_discovery.py</code>, <code>tests/services/test_discovery_scoring.py</code></li><li><strong>Cobertura:</strong> 65%</li><li><strong>Gaps conhecidos:</strong> Testes de dork spider com SerpAPI real (CI usa mock)</li></ul><h2 id="relacionamentos" tabindex="-1">Relacionamentos <a class="header-anchor" href="#relacionamentos" aria-label="Permalink to &quot;Relacionamentos&quot;">​</a></h2><ul><li><strong>Depende de:</strong> SerpAPI (dork spider), Telegram/Reddit APIs (social discovery), RDAP (WHOIS), Redis (rate limiting)</li><li><strong>Consumido por:</strong> Motor 2 (Crawler — WebCrawlerTarget), Motor 5 (Telegram), Motor 9 (Discord), Motor 13 (Reddit), Motor 25 (ShieldAI — tags)</li><li><strong>Conflita com:</strong> Motor 17 (SourceIntel — versao anterior deste motor)</li></ul>`,62)])])}const m=e(r,[["render",i]]);export{h as __pageData,m as default};
